use std::{io, time::SystemTime};

const BC_MAP: u8 = b'M';
const BC_MAP_UNTYPED: u8 = b'H';

const BC_END: u8 = b'Z';

const BC_LIST_DIRECT: u8 = 0x70;
const BC_LIST_DIRECT_UNTYPED: u8 = 0x78;
#[allow(dead_code)]
const BC_LIST_VARIABLE: u8 = 0x55;
const BC_LIST_FIXED: u8 = b'V';
#[allow(dead_code)]
const BC_LIST_VARIABLE_UNTYPED: u8 = 0x57;
const BC_LIST_FIXED_UNTYPED: u8 = 0x58;

const LIST_DIRECT_MAX: usize = 7;

const TRUE: u8 = b'T';
const FALSE: u8 = b'F';

const BC_DATE_MINUTE: u8 = 0x4b;
const BC_DATE: u8 = 0x4a;
const BC_LONG_ZERO: u8 = 0xe0;
const BC_LONG_BYTE_ZERO: u8 = 0xf8;
const BC_LONG_SHORT_ZERO: u8 = 0x3c;
const BC_INT_ZERO: u8 = 0x90;
const BC_INT_BYTE_ZERO: u8 = 0xc8;

const BC_LONG_INT: u8 = 0x59;

const BC_DOUBLE_ZERO: u8 = 0x5b;
const BC_DOUBLE_ONE: u8 = 0x5c;
const BC_DOUBLE_BYTE: u8 = 0x5d;
const BC_DOUBLE_SHORT: u8 = 0x5e;
const BC_DOUBLE_MILL: u8 = 0x5f;

const BC_STRING_DIRECT: u8 = 0x00;
const BC_STRING_SHORT: u8 = 0x30;
const BC_STRING_FINAL: u8 = b'S'; // final string
const BC_STRING_CHUNK: u8 = b'R'; // non-final string

const BC_BINARY: u8 = b'B'; // final chunk
const BC_BINARY_CHUNK: u8 = b'A'; // non-final chunk
const BC_BINARY_DIRECT: u8 = 0x20; // 1-byte length binary
const BC_BINARY_SHORT: u8 = 0x34; // 2-byte length binary

const BINARY_DIRECT_MAX: usize = 0x0f;
const BINARY_SHORT_MAX: usize = 0x3ff; // 0-1023 binary

#[inline]
pub(crate) fn put_null<W>(w: &mut W) -> io::Result<()>
where
    W: io::Write,
{
    w.write_all(&[b'N'])?;
    Ok(())
}

#[inline]
pub(crate) fn put_bytes<W>(w: &mut W, data: &[u8]) -> io::Result<()>
where
    W: io::Write,
{
    if data.is_empty() {
        return put_null(w);
    }

    let mut offset = 0;
    let size = data.len();

    const CHUNK: usize = 8192;
    const BATCH: usize = CHUNK - 3;

    while size - offset >= BATCH {
        w.write_all(&[BC_BINARY_CHUNK])?;
        w.write_all(&((CHUNK - 3) as u16).to_be_bytes())?;
        w.write_all(&data[offset..offset + BATCH])?;
        offset += BATCH;
    }

    let remaining = size - offset;

    if remaining <= BINARY_DIRECT_MAX {
        w.write_all(&[BC_BINARY_DIRECT + remaining as u8])?;
    } else if remaining <= BINARY_SHORT_MAX {
        w.write_all(&[
            BC_BINARY_SHORT + (remaining >> 8) as u8,
            (remaining & 0xff) as u8,
        ])?;
    } else {
        w.write_all(&[BC_BINARY, (remaining >> 8) as u8, (remaining & 0xff) as u8])?;
    }

    w.write_all(&data[offset..])?;

    Ok(())
}

#[inline]
pub(crate) fn put_i32<W>(w: &mut W, value: i32) -> io::Result<()>
where
    W: io::Write,
{
    const DIRECT: (i32, i32) = (-16, 47);
    const BYTE: (i32, i32) = (-2048, 2047);
    const SHORT: (i32, i32) = (-0x40000, 0x3ffff);

    const BC_INT_SHORT_ZERO: u8 = 0xd4;

    if DIRECT.0 <= value && value <= DIRECT.1 {
        w.write_all(&[((BC_INT_ZERO as i32) + value) as u8])?;
    } else if BYTE.0 <= value && value <= BYTE.1 {
        let first = (BC_INT_BYTE_ZERO as i32 + (value >> 8)) as u8;
        let second = (value & 0xff) as u8;
        w.write_all(&[first, second])?;
    } else if SHORT.0 <= value && value <= SHORT.1 {
        let first = ((BC_INT_SHORT_ZERO as i32) + (value >> 16)) as u8;
        let second = (value >> 8) as u8;
        let third = (value & 0xff) as u8;
        w.write_all(&[first, second, third])?;
    } else {
        w.write_all(&[b'I'])?;
        w.write_all(&value.to_be_bytes())?;
    }

    Ok(())
}

#[inline]
pub(crate) fn put_i64<W>(w: &mut W, value: i64) -> io::Result<()>
where
    W: io::Write,
{
    const MAX32: i64 = i32::MAX as i64;
    const MIN32: i64 = i32::MIN as i64;

    const LONG_DIRECT_MIN: i64 = -8;
    const LONG_DIRECT_MAX: i64 = 15;
    const LONG_BYTE_MIN: i64 = -2048;
    const LONG_BYTE_MAX: i64 = 2047;
    const LONG_SHORT_MIN: i64 = -0x40000;
    const LONG_SHORT_MAX: i64 = 0x3ffff;

    if LONG_DIRECT_MIN <= value && value <= LONG_DIRECT_MAX {
        w.write_all(&[(BC_LONG_ZERO as i64 + value) as u8])?;
    } else if LONG_BYTE_MIN <= value && value <= LONG_BYTE_MAX {
        let first = (BC_LONG_BYTE_ZERO as i64 + (value >> 8)) as u8;
        let second = (value & 0xff) as u8;
        w.write_all(&[first, second])?;
    } else if LONG_SHORT_MIN <= value && value <= LONG_SHORT_MAX {
        let first = (BC_LONG_SHORT_ZERO as i64 + (value >> 16)) as u8;
        let second = (value >> 8) as u8;
        let third = (value & 0xff) as u8;
        w.write_all(&[first, second, third])?;
    } else if MIN32 <= value && value <= MAX32 {
        w.write_all(&[BC_LONG_INT])?;
        w.write_all(&(value as i32).to_be_bytes())?;
    } else {
        w.write_all(&[b'L'])?;
        w.write_all(&value.to_be_bytes())?;
    }

    Ok(())
}

#[inline]
pub(crate) fn put_bool<W>(w: &mut W, value: bool) -> io::Result<()>
where
    W: io::Write,
{
    let byte = if value { TRUE } else { FALSE };
    w.write_all(&[byte])?;
    Ok(())
}

#[inline]
pub(crate) fn put_f64<W>(w: &mut W, v: f64) -> io::Result<()>
where
    W: io::Write,
{
    if v.is_finite() {
        let fract = v.fract();

        if fract == 0.0 {
            match v.trunc() as i64 {
                0 => {
                    w.write_all(&[BC_DOUBLE_ZERO])?;
                    return Ok(());
                }
                1 => {
                    w.write_all(&[BC_DOUBLE_ONE])?;
                    return Ok(());
                }
                v @ -0x80..0x80 => {
                    w.write_all(&[BC_DOUBLE_BYTE, (v & 0xff) as u8])?;
                    return Ok(());
                }
                v @ -0x8000..0x8000 => {
                    w.write_all(&[BC_DOUBLE_SHORT, (v >> 8) as u8, (v & 0xff) as u8])?;
                    return Ok(());
                }
                _ => (),
            }
        }

        if (1000f64 * fract).fract() == 0.0 {
            let v1000 = (1000f64 * v) as i32;
            w.write_all(&[BC_DOUBLE_MILL])?;
            w.write_all(&v1000.to_be_bytes())?;
            return Ok(());
        }
    }

    w.write_all(&[b'D'])?;
    w.write_all(&v.to_bits().to_be_bytes())?;
    Ok(())
}

#[inline]
pub(crate) fn put_system_time<W>(w: &mut W, value: SystemTime) -> io::Result<()>
where
    W: io::Write,
{
    let millis = value
        .duration_since(SystemTime::UNIX_EPOCH)
        .map(|it| it.as_millis() as i64)
        .unwrap_or(0);

    if millis % 60000i64 == 0 {
        let minutes = millis / 60000i64;
        match minutes >> 31 {
            0 | -1 => {
                w.write_all(&[BC_DATE_MINUTE])?;
                w.write_all(&(minutes as i32).to_be_bytes())?;
                return Ok(());
            }
            _ => (),
        }
    }
    w.write_all(&[BC_DATE])?;
    w.write_all(&millis.to_be_bytes())?;
    Ok(())
}

#[inline]
pub(crate) fn put_str<W>(w: &mut W, s: &str) -> io::Result<()>
where
    W: io::Write,
{
    const STRING_DIRECT_MAX: usize = 32 - 1;
    const STRING_SHORT_MAX: usize = 1024 - 1;

    let total = s.char_indices().count();
    let n = total / 0x8000;
    let tail = total % 0x8000;

    let mut cursor = s.chars();

    for _ in 0..n {
        w.write_all(&[BC_STRING_CHUNK])?;
        w.write_all(&0x8000u16.to_be_bytes())?;

        for _ in 0..0x8000 {
            if let Some(ch) = cursor.next() {
                write_char(w, ch)?;
            }
        }
    }

    if tail <= STRING_DIRECT_MAX {
        w.write_all(&[BC_STRING_DIRECT + tail as u8])?;
    } else if tail <= STRING_SHORT_MAX {
        let first = (BC_STRING_SHORT as usize) + tail >> 8;
        w.write_all(&[first as u8, (0xff & tail) as u8])?;
    } else {
        w.write_all(&[BC_STRING_FINAL])?;
        w.write_all(&(tail as u16).to_be_bytes())?;
    }

    for ch in cursor {
        write_char(w, ch)?;
    }

    Ok(())
}

pub(crate) fn begin_list<W>(w: &mut W, typ: Option<&str>, length: usize) -> io::Result<()>
where
    W: io::Write,
{
    match typ {
        None => {
            if length <= LIST_DIRECT_MAX {
                w.write_all(&[BC_LIST_DIRECT_UNTYPED + length as u8])?;
            } else {
                w.write_all(&[BC_LIST_FIXED_UNTYPED])?;
                put_i32(w, length as i32)?;
            }
        }
        Some(name) => {
            if length <= LIST_DIRECT_MAX {
                w.write_all(&[BC_LIST_DIRECT + length as u8])?;
                put_str(w, name)?;
            } else {
                w.write_all(&[BC_LIST_FIXED])?;
                put_str(w, name)?;
                put_i32(w, length as i32)?;
            }
        }
    }

    Ok(())
}

#[inline]
pub(crate) fn begin_map<W>(w: &mut W, typ: Option<&str>) -> io::Result<()>
where
    W: io::Write,
{
    match typ {
        None => {
            w.write_all(&[BC_MAP_UNTYPED])?;
        }
        Some(name) => {
            w.write_all(&[BC_MAP])?;
            put_str(w, name)?;
        }
    }

    Ok(())
}

#[inline]
pub(crate) fn end_map<W>(w: &mut W) -> io::Result<()>
where
    W: io::Write,
{
    w.write_all(&[BC_END])?;
    Ok(())
}

#[inline(always)]
fn write_char<W>(w: &mut W, c: char) -> io::Result<()>
where
    W: io::Write,
{
    let ch = c as u32;
    if ch < 0x80 {
        w.write_all(&[ch as u8])?;
    } else if ch < 0x800 {
        let first = 0xc0 + ((ch >> 6) & 0x1f) as u8;
        let second = 0x80 + (ch & 0x3f) as u8;
        w.write_all(&[first, second])?;
    } else {
        let first = 0xe0 + ((ch >> 12) & 0xf) as u8;
        let second = 0x80 + ((ch >> 6) & 0x3f) as u8;
        let third = 0x80 + (ch & 0x3f) as u8;
        w.write_all(&[first, second, third])?;
    }
    Ok(())
}

#[cfg(test)]
mod tests {
    use super::*;

    fn init() {
        pretty_env_logger::try_init_timed().ok();
    }

    #[test]
    fn test_encode_bool() -> io::Result<()> {
        init();

        let to_hex = |b: bool| -> io::Result<String> {
            let mut buf = vec![];
            put_bool(&mut buf, b)?;
            Ok(hex::encode(&buf))
        };

        assert_eq!("54", to_hex(true)?);
        assert_eq!("46", to_hex(false)?);

        Ok(())
    }

    #[test]
    fn test_encode_i64() -> io::Result<()> {
        init();

        let to_hex = |v: i64| -> io::Result<String> {
            let mut buf = vec![];
            put_i64(&mut buf, v)?;
            Ok(hex::encode(&buf))
        };

        assert_eq!("e0", to_hex(0)?);
        assert_eq!("d8", to_hex(-8)?);
        assert_eq!("ef", to_hex(15)?);
        assert_eq!("f000", to_hex(-2048)?);
        assert_eq!("f700", to_hex(-256)?);
        assert_eq!("ffff", to_hex(2047)?);
        assert_eq!("380000", to_hex(-262144)?);
        assert_eq!("3fffff", to_hex(262143)?);
        assert_eq!("4c0000000080000000", to_hex(2147483648)?);

        Ok(())
    }

    #[test]
    fn test_encode_i32() -> io::Result<()> {
        init();

        let to_hex = |v: i32| -> io::Result<String> {
            let mut buf = vec![];
            put_i32(&mut buf, v)?;
            Ok(hex::encode(&buf))
        };

        assert_eq!("90", to_hex(0)?);
        assert_eq!("80", to_hex(-16)?);
        assert_eq!("bf", to_hex(47)?);
        assert_eq!("c000", to_hex(-2048)?);
        assert_eq!("c700", to_hex(-256)?);
        assert_eq!("cfff", to_hex(2047)?);

        assert_eq!("d00000", to_hex(-262144)?);
        assert_eq!("d7ffff", to_hex(262143)?);

        Ok(())
    }

    #[test]
    fn test_encode_f64() -> io::Result<()> {
        init();

        let to_hex = |v: f64| -> io::Result<String> {
            let mut buf = vec![];
            put_f64(&mut buf, v)?;
            Ok(hex::encode(&buf))
        };

        assert_eq!("5b", to_hex(0.0)?);
        assert_eq!("5c", to_hex(1.0)?);
        assert_eq!("5d80", to_hex(-128.0)?);
        assert_eq!("5d7f", to_hex(127.0)?);
        assert_eq!("5e8000", to_hex(-32768.0)?);
        assert_eq!("5e7fff", to_hex(32767.0)?);
        assert_eq!("44400921fb54442d18", to_hex(std::f64::consts::PI)?);
        assert_eq!("447ff0000000000000", to_hex(f64::INFINITY)?);
        assert_eq!("44fff0000000000000", to_hex(f64::NEG_INFINITY)?);
        assert_eq!("447ff8000000000000", to_hex(f64::NAN)?);

        Ok(())
    }

    #[test]
    fn test_encode_system_time() -> io::Result<()> {
        init();

        let to_hex = |v: SystemTime| -> io::Result<String> {
            let mut buf = vec![];
            put_system_time(&mut buf, v)?;
            Ok(hex::encode(&buf))
        };

        use chrono::DateTime;

        {
            let rfc3339_str = "2026-06-10T15:16:17+08:00";
            let datetime = DateTime::parse_from_rfc3339(rfc3339_str).unwrap();
            let system_time: SystemTime = SystemTime::from(datetime);

            assert_eq!("4a0000019eb06395e8", to_hex(system_time)?);
        }
        {
            let rfc3339_str = "2026-06-10T15:16:00+08:00";
            let datetime = DateTime::parse_from_rfc3339(rfc3339_str).unwrap();
            let system_time: SystemTime = SystemTime::from(datetime);

            assert_eq!("4b01c4f374", to_hex(system_time)?);
        }

        Ok(())
    }

    #[test]
    fn test_encode_str() -> io::Result<()> {
        init();

        let to_hex = |v: &str| -> io::Result<String> {
            let mut buf = vec![];
            put_str(&mut buf, v)?;
            Ok(hex::encode(&buf))
        };

        assert_eq!("00", to_hex("")?);
        assert_eq!("0568656c6c6f", to_hex("hello")?);
        assert_eq!("01c383", to_hex("\u{00c3}")?);

        assert_eq!(
            "",
            to_hex(&String::from("foo".repeat(1023)))?
        );

        Ok(())
    }

    #[test]
    fn test_encode_binary() -> io::Result<()> {
        init();

        let to_hex = |v: &[u8]| -> io::Result<String> {
            let mut buf = vec![];
            put_bytes(&mut buf, v)?;
            Ok(hex::encode(&buf))
        };

        // direct
        {
            assert_eq!("2568656c6c6f", to_hex(&b"hello"[..])?);
            assert_eq!(
                "2f48656c6c6f20576f726c6421212121",
                to_hex(&b"Hello World!!!!"[..])?
            );

            assert_eq!(
                "341048656c6c6f20576f726c642121212121",
                to_hex(&b"Hello World!!!!!"[..])?
            );
        }

        // short
        {
            assert_eq!(
                "341148656c6c6f20576f726c64212121212121",
                to_hex(&b"Hello World!!!!!!"[..])?
            );
            let b = "x".repeat(1024);
            assert_eq!(
                "",
                to_hex(b.as_bytes())?
            )
        }

        // final
        {
            let b = "x".repeat(1025);
            assert_eq!(
                "",
                to_hex(b.as_bytes())?
            )
        }

        // chunked
        {
            let b = {
                let mut v = vec![];
                for _ in 0..8192 {
                    v.push(b'x');
                }
                v.push(b'y');
                v
            };

            assert_eq!(
                "",
                to_hex(&b)?,
            );
        }

        Ok(())
    }

    #[test]
    fn test_list() -> io::Result<()> {
        // untyped i64
        {
            let to_hex = |v: &[i64]| -> io::Result<String> {
                let mut w = vec![];
                let size = v.len();
                begin_list(&mut w, None, size)?;
                for next in v {
                    put_i64(&mut w, *next)?;
                }
                Ok(hex::encode(&w))
            };

            assert_eq!("78", to_hex(&[])?);
            assert_eq!("7bf86ff8def94d", to_hex(&[111, 222, 333])?);
            assert_eq!(
                "5899f86ff8def94df9bcfa2bfa9afb09fb78fbe7",
                to_hex(&[111, 222, 333, 444, 555, 666, 777, 888, 999])?
            );
        }

        // untyped string
        {
            let to_hex = |v: &[&str]| -> io::Result<String> {
                let mut w = vec![];
                let size = v.len();
                begin_list(&mut w, None, size)?;
                for next in v {
                    put_str(&mut w, *next)?;
                }
                Ok(hex::encode(&w))
            };

            assert_eq!("78", to_hex(&[])?);
            assert_eq!(
                "7b03666f6f0362617203717578",
                to_hex(&["foo", "bar", "qux"])?
            );
        }

        // typed
        {
            let typ = "java.util.LinkedList";

            let to_hex = |typ: &str, v: &[i64]| -> io::Result<String> {
                let mut w = vec![];
                let size = v.len();
                begin_list(&mut w, Some(typ), size)?;
                for next in v {
                    put_i64(&mut w, *next)?;
                }
                Ok(hex::encode(&w))
            };

            assert_eq!(
                "70146a6176612e7574696c2e4c696e6b65644c697374",
                to_hex(typ, &[])?
            );
            assert_eq!(
                "73146a6176612e7574696c2e4c696e6b65644c697374f86ff8def94d",
                to_hex(typ, &[111, 222, 333])?
            );
            assert_eq!(
                "56146a6176612e7574696c2e4c696e6b65644c69737499f86ff8def94df9bcfa2bfa9afb09fb78fbe7",
                to_hex(typ, &[111, 222, 333, 444, 555, 666, 777, 888, 999])?
            );
        }

        Ok(())
    }

    #[test]
    fn test_map() -> io::Result<()> {
        init();

        use std::collections::BTreeMap;

        let mut m: BTreeMap<i32, &str> = Default::default();
        m.insert(1, "foo");
        m.insert(2, "bar");
        m.insert(3, "qux");

        // untyped
        {
            let mut w = vec![];
            begin_map(&mut w, None)?;

            for (k, v) in &m {
                put_i32(&mut w, *k)?;
                put_str(&mut w, v)?;
            }

            end_map(&mut w)?;

            let s = hex::encode(&w);

            info!("{:?}: {}", &m, &s);

            assert!(!s.is_empty());
        }

        // typed
        {
            let mut w = vec![];
            begin_map(&mut w, Some("java.util.TreeMap"))?;

            for (k, v) in &m {
                put_i32(&mut w, *k)?;
                put_str(&mut w, v)?;
            }

            end_map(&mut w)?;

            let s = hex::encode(&w);

            info!("{:?}: {}", &m, &s);

            assert_eq!(
                "4d116a6176612e7574696c2e547265654d61709103666f6f920362617293037175785a",
                &s
            );
        }

        Ok(())
    }
}
